// Strategy 1: <user-query> / <model-response> custom elements (Gemini 2024+)
var rawTitle = document.title || '';
var title = rawTitle.replace(/\s*[-\u2013]\s*Gemini\s*$/i, '').trim() || 'Gemini Chat';

var pairs = [];

var userQueryEls = document.querySelectorAll('user-query');
var modelRespEls = document.querySelectorAll('model-response');
if (userQueryEls.length > 0 || modelRespEls.length > 0) {
  var max1 = Math.max(userQueryEls.length, modelRespEls.length);
  for (var i = 0; i < max1; i++) {
    if (userQueryEls[i]) pairs.push({ role: 'User',   text: userQueryEls[i].innerText.trim() });
    if (modelRespEls[i]) pairs.push({ role: 'Gemini', text: modelRespEls[i].innerText.trim() });
  }
}

// Strategy 2: data-message-author-role attribute
if (pairs.length === 0) {
  var msgEls = document.querySelectorAll('[data-message-author-role]');
  for (var j = 0; j < msgEls.length; j++) {
    var role = msgEls[j].getAttribute('data-message-author-role') === 'user' ? 'User' : 'Gemini';
    pairs.push({ role: role, text: msgEls[j].innerText.trim() });
  }
}

// Strategy 3: class-based fallback
if (pairs.length === 0) {
  var userEls  = document.querySelectorAll('.query-text, .user-query-text');
  var modelEls = document.querySelectorAll('.model-response-text, .response-content');
  var max3 = Math.max(userEls.length, modelEls.length);
  for (var k = 0; k < max3; k++) {
    if (userEls[k])  pairs.push({ role: 'User',   text: userEls[k].innerText.trim() });
    if (modelEls[k]) pairs.push({ role: 'Gemini', text: modelEls[k].innerText.trim() });
  }
}

var validPairs = pairs.filter(function(p) { return p.text; });
var lines = validPairs.map(function(p) { return '**' + p.role + ':**\n\n' + p.text; });

var content = lines.length > 0
  ? lines.join('\n\n---\n\n')
  : '<!-- No conversation messages found. Run this on a conversation page (URL ends with /app/XXXXXX). -->';

console.log('[Gemini Download] title:', title, '| messages found:', validPairs.length);

automaSetVariable('title',    title);
automaSetVariable('content',  content);
automaSetVariable('msgCount', String(validPairs.length));
automaNextBlock({ data: 'scraped ' + validPairs.length + ' messages from: ' + title });

var title   = automaRefData('variables', 'title')   || 'gemini';
var content = automaRefData('variables', 'content') || '';

var today    = new Date().toISOString().slice(0, 10);
var markdown = '# ' + title + '\n\n'
  + '> Downloaded: ' + today + '  \n'
  + '> Source: ' + location.href + '\n\n'
  + '---\n\n'
  + content + '\n';

var filename = (title
  .replace(/[^a-z0-9]/gi, '_')
  .replace(/_+/g, '_')
  .replace(/^_|_$/g, '')
  .toLowerCase() || 'gemini') + '.md';

var blob = new Blob([markdown], { type: 'text/markdown' });
var url  = URL.createObjectURL(blob);
var a    = document.createElement('a');
a.href     = url;
a.download = filename;
document.body.appendChild(a);
a.click();
setTimeout(function() { URL.revokeObjectURL(url); if (a.parentNode) a.parentNode.removeChild(a); }, 1000);

console.log('[Gemini Download] File saved as:', filename);
automaSetVariable('filename', filename);
automaNextBlock({ data: 'saved: ' + filename });
